var frameIndex = GetInt(parameters, "frameIndex", 0);
var size = context.TileSize;
var result = new PixelBuffer(size, size);
if (src == null) return result;
var srcSize = src.Width;
var cellW = srcSize / cols;
var cellH = srcSize / rows;
var totalFrames = cols * rows;
var frame = ((frameIndex % totalFrames) + totalFrames) % totalFrames;
var srcCol = frame % cols;
var srcRow = frame / cols;
result.ParallelForEachPixel((x, y) =>
{
    var srcX = srcCol * cellW + (int)((float)x / size * cellW);
    var srcY = srcRow * cellH + (int)((float)y / size * cellH);
    srcX = Math.Clamp(srcX, 0, srcSize - 1);
    srcY = Math.Clamp(srcY, 0, srcSize - 1);
    var (r, g, b, a) = src.GetPixel(srcX, srcY);
    result.SetPixel(x, y, r, g, b, a);
});
return result;
